import Header from "./components/Header";

function App() {
  return (
    <div>
      <Header />
      <div style={{ padding: "50px", textAlign: "center" }}>
        <h1>MBTI აპლიკაცია მუშაობს!</h1>
        <p>React და Node backend მზად არიან.</p>
      </div>
    </div>
  );
}

export default App;
